//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagekafkaimport("context""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/kafka""github.com/hashicorp/aws-sdk-go-base/v2/awsv1shim/v2/tfawserr""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry""github.com/hashicorp/terraform-provider-aws/internal/tfresource")funcFindClusterByARN(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.ClusterInfo,error){input:=&kafka.DescribeClusterInput{ClusterArn:aws.String(arn),}output,err:=conn.DescribeClusterWithContext(ctx,input)iftfawserr.ErrCodeEquals(err,kafka.ErrCodeNotFoundException){returnnil,&retry.NotFoundError{LastError:err,LastRequest:input,}}iferr!=nil{returnnil,err}ifoutput==nil||output.ClusterInfo==nil{returnnil,tfresource.NewEmptyResultError(input)}returnoutput.ClusterInfo,nil}funcfindClusterV2ByARN(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.Cluster,error){input:=&kafka.DescribeClusterV2Input{ClusterArn:aws.String(arn),}output,err:=conn.DescribeClusterV2WithContext(ctx,input)iftfawserr.ErrCodeEquals(err,kafka.ErrCodeNotFoundException){returnnil,&retry.NotFoundError{LastError:err,LastRequest:input,}}iferr!=nil{returnnil,err}ifoutput==nil||output.ClusterInfo==nil{returnnil,tfresource.NewEmptyResultError(input)}returnoutput.ClusterInfo,nil}funcFindClusterOperationByARN(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.ClusterOperationInfo,error){input:=&kafka.DescribeClusterOperationInput{ClusterOperationArn:aws.String(arn),}output,err:=conn.DescribeClusterOperationWithContext(ctx,input)iftfawserr.ErrCodeEquals(err,kafka.ErrCodeNotFoundException){returnnil,&retry.NotFoundError{LastError:err,LastRequest:input,}}iferr!=nil{returnnil,err}ifoutput==nil||output.ClusterOperationInfo==nil{returnnil,tfresource.NewEmptyResultError(input)}returnoutput.ClusterOperationInfo,nil}funcFindConfigurationByARN(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.DescribeConfigurationOutput,error){input:=&kafka.DescribeConfigurationInput{Arn:aws.String(arn),}output,err:=conn.DescribeConfigurationWithContext(ctx,input)iftfawserr.ErrMessageContains(err,kafka.ErrCodeBadRequestException,"ConfigurationARNdoesnotexist"){returnnil,&retry.NotFoundError{LastError:err,LastRequest:input,}}iferr!=nil{returnnil,err}ifoutput==nil{returnnil,tfresource.NewEmptyResultError(input)}returnoutput,nil}//FindScramSecretsreturnsthematchingMSKCluster'sassociatedsecretsfuncFindScramSecrets(ctxcontext.Context,conn*kafka.Kafka,clusterArnstring)([]*string,error){input:=&kafka.ListScramSecretsInput{ClusterArn:aws.String(clusterArn),}varscramSecrets[]*stringerr:=conn.ListScramSecretsPagesWithContext(ctx,input,func(page*kafka.ListScramSecretsOutput,lastPagebool)bool{ifpage==nil{return!lastPage}scramSecrets=append(scramSecrets,page.SecretArnList...)return!lastPage})returnscramSecrets,err}funcFindServerlessClusterByARN(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.Cluster,error){output,err:=findClusterV2ByARN(ctx,conn,arn)iferr!=nil{returnnil,err}ifoutput.Serverless==nil{returnnil,tfresource.NewEmptyResultError(arn)}returnoutput,nil}